import{_ as o,o as t,c as a,a8 as i}from"./chunks/framework.DvHWw5tv.js";const m=JSON.parse('{"title":"useCheckComputed","description":"","frontmatter":{},"headers":[],"relativePath":"en/design/hooks/useCheck.md","filePath":"en/design/hooks/useCheck.md"}'),n={name:"en/design/hooks/useCheck.md"};function s(d,e,r,l,c,h){return t(),a("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1776410922000"},[...e[0]||(e[0]=[i('<h1 id="usecheckcomputed" tabindex="-1">useCheckComputed <a class="header-anchor" href="#usecheckcomputed" aria-label="Permalink to “useCheckComputed”">​</a></h1><h2 id="dedicated-logic-hooks-for-radio-and-checkbox-components" tabindex="-1">Dedicated Logic Hooks for Radio and Checkbox Components <a class="header-anchor" href="#dedicated-logic-hooks-for-radio-and-checkbox-components" aria-label="Permalink to “Dedicated Logic Hooks for Radio and Checkbox Components”">​</a></h2><h3 id="pain-points" tabindex="-1">Pain Points <a class="header-anchor" href="#pain-points" aria-label="Permalink to “Pain Points”">​</a></h3><p>Radio and Checkbox are among the most common interactive controls in forms, yet their implementation often involves a significant amount of repetitive logic:</p><ul><li>The logic for determining the <code>checked</code> state must be compatible with both standalone usage and usage within a Group wrapper.</li><li>The disabled state must merge the component&#39;s own <code>disabled</code> prop with the Group&#39;s <code>disabled</code> context.</li><li>Value changes must correctly handle updates for arrays (Checkbox) versus single values (Radio), and trigger both <code>update:modelValue</code> and <code>change</code> events.</li><li>Integration with form components (e.g., Form / FormItem) requires lifecycle management for field registration, resetting, and clearing validation.</li><li>Class states (e.g., <code>--checked</code>, <code>--disabled</code>) must be updated reactively.</li></ul><p>Implementing this logic independently in each component leads not only to code redundancy but also to high risks of inconsistent behavior and overlooked edge cases.</p><h2 id="design-goals" tabindex="-1">Design Goals <a class="header-anchor" href="#design-goals" aria-label="Permalink to “Design Goals”">​</a></h2><p>The <code>useCheckComputed.ts</code> file centralizes all common logic for radio and checkbox components. Through multiple small, focused composable hooks, it provides a <strong>unified, reusable, and type-safe</strong> solution, allowing the implementation of Radio and Checkbox components to be extremely streamlined while offering perfect support for:</p><ul><li>Standalone usage</li><li>Usage within a Group wrapper</li><li>Integration with Form / FormItem</li><li>Two-way binding with <code>v-model</code></li></ul><h2 id="core-hooks-composition" tabindex="-1">Core Hooks Composition <a class="header-anchor" href="#core-hooks-composition" aria-label="Permalink to “Core Hooks Composition”">​</a></h2><table tabindex="0"><thead><tr><th>Hook</th><th>Responsibility</th><th>Key Features</th></tr></thead><tbody><tr><td><strong>useFormField</strong></td><td>Handles field registration, resetting, and clearing validation with FormItem.</td><td>Automatically registers on <code>onMounted</code> and unregisters on <code>onBeforeUnmount</code>; supports <code>resetField</code>.</td></tr><tr><td><strong>useInputState</strong></td><td>Computes <code>isChecked</code> and <code>isDisabled</code> states, compatible with both Group and standalone modes.</td><td>Prioritizes Group&#39;s <code>modelValue</code>/<code>disabled</code>; supports comparison with both arrays and single values.</td></tr><tr><td><strong>useInputClasses</strong></td><td>Generates an array of reactive class names based on checked/disabled states.</td><td>Concise and reusable; supports custom prefixes (e.g., <code>my-radio</code>, <code>my-checkbox</code>).</td></tr><tr><td><strong>useInputChange</strong></td><td>Handles <code>change</code> events, correctly updating <code>modelValue</code> (array or single) and firing events.</td><td>Distinguishes between Checkbox (array manipulation) and Radio (direct assignment); prevents trigger when disabled.</td></tr></tbody></table><h2 id="design-highlights" tabindex="-1">Design Highlights <a class="header-anchor" href="#design-highlights" aria-label="Permalink to “Design Highlights”">​</a></h2><ul><li><strong>Flawless Group Compatibility</strong>: Retrieves <code>radioGroup</code> or <code>checkboxGroup</code> context via <code>inject</code>. All state and change logic defers to the Group context first, eliminating duplicate implementations.</li><li><strong>Type-Safe Generics</strong>: <code>GroupContext&lt;M&gt;</code> supports arbitrary <code>modelValue</code> types. <code>useInputState</code> and <code>useInputChange</code> use generics to accurately infer differences between Radio (single value) and Checkbox (array).</li><li><strong>Minimal Intrusiveness</strong>: Each hook has a single responsibility. Components only need to compose the necessary hooks without concern for the underlying implementation details.</li><li><strong>Deep Integration with Form System</strong>: Automatically handles field registration and resetting, working seamlessly with FormItem&#39;s validation and <code>reset</code> functionality without requiring extra code.</li><li><strong>Rigorous Edge Case Handling</strong>: Prevents changes when disabled; uses <code>String()</code> for value comparison to avoid type pitfalls; employs spread operators for array updates to prevent reference issues.</li></ul><h2 id="design-value" tabindex="-1">Design Value <a class="header-anchor" href="#design-value" aria-label="Permalink to “Design Value”">​</a></h2><p><code>useCheckComputed</code> abstracts the complex state management, event handling, and form integration logic previously scattered across Radio and Checkbox implementations into four small, composable hooks, achieving:</p><ul><li><strong>Highly consistent behavior</strong> (seamless switching between standalone and Group modes)</li><li><strong>Minimal code</strong> (component logic under 30 lines)</li><li><strong>Ease of maintenance and extension</strong> (new features can be added by enhancing this single file)</li><li><strong>Flawless collaboration</strong> with other component library systems (e.g., Form, Class/Style Hooks)</li></ul>',16)])])}const p=o(n,[["render",s]]);export{m as __pageData,p as default};
